"""matplotlib.font_manager — font management stubs."""


class FontProperties:
    def __init__(self, family=None, style=None, variant=None, weight=None,
                 stretch=None, size=None, fname=None, math_fontfamily=None):
        self._family = family or ['sans-serif']
        self._style = style or 'normal'
        self._variant = variant or 'normal'
        self._weight = weight or 'normal'
        self._stretch = stretch or 'normal'
        self._size = size or 12
        self._fname = fname

    def get_family(self): return self._family
    def set_family(self, family): self._family = family if isinstance(family, list) else [family]
    def get_style(self): return self._style
    def set_style(self, style): self._style = style
    def get_variant(self): return self._variant
    def set_variant(self, variant): self._variant = variant
    def get_weight(self): return self._weight
    def set_weight(self, weight): self._weight = weight
    def get_stretch(self): return self._stretch
    def set_stretch(self, stretch): self._stretch = stretch
    def get_size(self): return self._size
    def set_size(self, size): self._size = size
    def get_name(self): return self._family[0] if self._family else 'sans-serif'
    def set_name(self, name): self._family = [name]
    def get_file(self): return self._fname
    def set_file(self, fname): self._fname = fname
    def copy(self):
        return FontProperties(
            family=list(self._family), style=self._style, variant=self._variant,
            weight=self._weight, stretch=self._stretch, size=self._size, fname=self._fname
        )


class FontManager:
    def __init__(self, size=None, weight='normal'):
        self.defaultFamily = {'ttf': 'DejaVu Sans', 'afm': 'Helvetica'}
        self.defaultSize = size
        self.defaultWeight = weight
        self.ttflist = []
        self.afmlist = []

    def findfont(self, prop, fontext='ttf', directory=None, fallback_to_default=True, rebuild_if_missing=True):
        return ''

    def get_default_size(self):
        return self.defaultSize or 12


fontManager = FontManager()

def findfont(prop, **kwargs):
    return fontManager.findfont(prop, **kwargs)

