def FontEntry(fname='', name='', style='normal', variant='normal',
              weight='normal', stretch='normal', size='medium'):
    return type('FontEntry', (), {
        'fname': fname, 'name': name, 'style': style,
        'variant': variant, 'weight': weight, 'stretch': stretch, 'size': size
    })()

